365	// handleIssuerBasedCA handles the creation of CA ConfigMap from issuer secret and volume mounting.
366	func (r *Reconciler) handleIssuerBasedCA(deployment *appsv1.Deployment, istiocsr *v1alpha1.IstioCSR, resourceLabels map[string]string) error {
367		var (
368			issuerConfig certmanagerv1.IssuerConfig
369		)
370	
371		obj, err := r.getIssuer(istiocsr)
372		if err != nil {
373			return common.FromClientError(err, "failed to fetch issuer")
374		}
375	
376		issuerRefKind := strings.ToLower(istiocsr.Spec.IstioCSRConfig.CertManager.IssuerRef.Kind)
377		switch issuerRefKind {
378		case clusterIssuerKind:
379			clusterIssuer, ok := obj.(*certmanagerv1.ClusterIssuer)
380			if !ok {
381				return common.FromClientError(fmt.Errorf("failed to convert to ClusterIssuer"), "failed to fetch issuer")
382			}
383			issuerConfig = clusterIssuer.Spec.IssuerConfig
384		case issuerKind:
385			issuer, ok := obj.(*certmanagerv1.Issuer)
386			if !ok {
387				return common.FromClientError(fmt.Errorf("failed to convert to Issuer"), "failed to fetch issuer")
388			}
389			issuerConfig = issuer.Spec.IssuerConfig
390		}
391	
392		shouldUpdateVolume := false
393	
394		if issuerConfig.CA != nil && issuerConfig.CA.SecretName != "" {
395			if err := r.createCAConfigMapFromIssuerSecret(istiocsr, issuerConfig, resourceLabels); err != nil {
396				return common.FromClientError(err, "failed to create CA ConfigMap")
397			}
398			shouldUpdateVolume = true
399		}
400	
401		if issuerConfig.CA == nil {
402			if err := r.createCAConfigMapFromIstiodCertificate(istiocsr, resourceLabels); err != nil {
403				return common.FromClientError(err, "failed to create CA ConfigMap")
404			}
405			shouldUpdateVolume = true
406		}
407	
408		if shouldUpdateVolume {
409			updateVolumeWithIssuerCA(deployment)
410		}
411	
412		return nil
413	}
